const payload = items[0]?.json || {};
return [{
  json: {
    ok: true,
    sourceTotal: payload.source_total ?? null,
    duplicateCount: payload.duplicate_count ?? null,
    candidateCount: payload.candidate_count ?? null,
    importedCount: payload.imported_count ?? null,
    imageCount: payload.image_count ?? null,
    failureCount: Array.isArray(payload.failures) ? payload.failures.length : 0,
    importedItems: payload.imported_items ?? [],
    checkedAt: new Date().toISOString(),
  }
}];
